                                           const at::Tensor& w,
                                           const at::Tensor& b,
                                           int64_t max_dim) {
    // Output shape [B, 1]
    TORCH_CHECK(x.dim() == 2, \"x must be 2D\");
    TORCH_CHECK(w.dim() == 2, \"w must be 2D\");
    TORCH_CHECK(b.dim() == 1, \"b must be 1D\");
    TORCH_CHECK(x.size(1) == w.size(1), \"in_features mismatch between x and w\");
    TORCH_CHECK(w.size(0) == b.size(0), \"out_features mismatch between w and b\");

    auto B = x.size(0);
    at::Tensor y = at::empty({B, 1}, x.options());

    EXEC_NPU_CMD(aclnnGemmMaxSubtractGeluCustom, x, w, b, (int)max_dim, y);
    return y;
}

